"""
stemlite: a tiny, zero-dependency collection of English stemmers.

Pure standard library implementations of the Porter, Snowball (Porter2),
and Lancaster stemming algorithms, plus a small registry so callers can pick
a stemmer by name. Designed as a shared, self-contained dependency for search
libraries (minsearch, zerosearch, sqlitesearch).

Example:
    >>> from stemlite import get_stemmer, porter_stemmer
    >>> porter_stemmer("running")
    'run'
    >>> get_stemmer("porter")("running")
    'run'
    >>> get_stemmer(None)("Running")   # no-op: lowercases only
    'running'
"""

from .porter import porter_stemmer
from .snowball import snowball_stemmer
from .lancaster import lancaster_stemmer
from .base import get_stemmer, STEMMERS

__version__ = "0.1.0"

__all__ = [
    "porter_stemmer",
    "snowball_stemmer",
    "lancaster_stemmer",
    "get_stemmer",
    "STEMMERS",
    "__version__",
]
